    /**
     * An implementation of the merge sort algorithm to sort an array of non-negative integers.
     * This method sorts the array in ascending order and handles unexpected inputs.
     *
     * @param arr The input array of non-negative integers to be sorted.
     */
    public static void mergeSort(int[] arr) {
        if (arr == null) {
            throw new IllegalArgumentException("Input array cannot be null.");
        }

        for (int i = 0; i < arr.length; i++) {
            if (arr[i] < 0) {
                throw new IllegalArgumentException("Array elements must be non-negative.");
            }
        }

        if (arr.length <= 1) {
            return;
        }

        int mid = arr.length / 2;
        int[] left = Arrays.copyOfRange(arr, 0, mid);
        int[] right = Arrays.copyOfRange(arr, mid, arr.length);

        mergeSort(left);
        mergeSort(right);
        merge(arr, left, right);
    }

    /**
     * Merges two sorted arrays into one sorted array.
     *
     * @param arr The target array to hold the sorted elements.
     * @param left The left sub-array.
     * @param right The right sub-array.
     */
    private static void merge(int[] arr, int[] left, int[] right) {
        int i = 0, j = 0, k = 0;

        while (i < left.length && j < right.length) {
            if (left[i] <= right[j]) {
