#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use Text::PDF::Text;

# Function to extract text from PDF
sub extract_text_from_pdf {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);
    my $text = Text::PDF::Text->new($pdf);

    my $text_content = '';
    while (my $text_page = $text->next_page()) {
        $text_content .= $text_page->text;
    }

    return $text_content;
}

